`timescale 1 ns / 1 ps
module `IP_MODULE_NAME(efx_csi2_rx_top) #(
    parameter HS_DATA_WIDTH = 16,
    parameter tINIT_NS = 400000,
	parameter CLOCK_FREQ_MHZ = 100,
    parameter NUM_DATA_LANE = 4,
    parameter PACK_TYPE = 4'b1111,
    parameter AREGISTER = 8,
